print("\n=== DIMENSIONES DEL DATASET ===")
print("Filas:", len(df), "| Columnas:", df.shape[1])

print("\n=== NULOS POR COLUMNA (valores faltantes) ===")
print(df.isna().sum())



# ------------------------------------------------------------
# 9) SUGERENCIA PEDAGÓGICA
